function smokeProbeResponse(path: string): Record<string, unknown> {
  if (path === "/readyz") {
    return {
      ready: true,
      startedAt: "2026-06-30T00:00:00.000Z",
      uptimeMs: 0,
      checks: {
        queueRecovery: "completed",
        staleRunCleanup: "disabled",
      },
    };
  }
  return {
    ok: true,
    startedAt: "2026-06-30T00:00:00.000Z",
    uptimeMs: 0,
  };
}

