test("loom harness platform-concurrency-audit gates multi-agent AGS cutover evidence", async () => {
  const root = await tempDir("loom-cli-platform-concurrency-audit");
  const cutoverPath = join(root, "cutover-report.json");
  const smokePath = join(root, "smoke.json");
  const reportPath = join(root, "concurrency-audit.json");

  await writeFile(cutoverPath, JSON.stringify({
    ok: true,
    tenant: "alice",
    controlPlaneProvider: "agent-git-service",
    serverConcurrencyAdmissionOk: true,
    serverConcurrencyAdmissionSchemaVersion: "loom-concurrency-admission/v1",
    serverConcurrencyAdmissionRunWorkspaceIsolation: "project",
    serverConcurrencyAdmissionActiveRunClaimScope: "project",
    serverConcurrencyAdmissionQueueBlockedReasons: ["tenant_active_run_limit", "project_active_workspace", "persisted_running_run"],
    serverConcurrencyAdmissionRunControlCrossServer: true,
    serverConcurrencyAdmissionMissing: [],
    tenantConcurrencyAdmissionOk: true,
    tenantConcurrencyAdmissionSchemaVersion: "loom-concurrency-admission/v1",
    tenantConcurrencyAdmissionRunWorkspaceIsolation: "project",
    tenantConcurrencyAdmissionActiveRunClaimScope: "project",
    tenantConcurrencyAdmissionQueueBlockedReasons: ["tenant_active_run_limit", "project_active_workspace", "persisted_running_run"],
    tenantConcurrencyAdmissionRunControlCrossServer: true,
    tenantConcurrencyAdmissionMissing: [],
    agentGitService: {
      checked: true,
      ready: true,
      readyProjectCount: 1,
      missingProjects: [],
    },
  }), "utf8");
  await writeFile(smokePath, JSON.stringify({
    ok: true,
    status: "passed",
    serverControlPlaneProvider: "agent-git-service",
    tenantControlPlaneProvider: "agent-git-service",
    serverConcurrencyAdmissionChecked: true,
    serverConcurrencyAdmissionSchemaVersion: "loom-concurrency-admission/v1",
    serverConcurrencyAdmissionRunWorkspaceIsolation: "project",
    serverConcurrencyAdmissionActiveRunClaimScope: "project",
    serverConcurrencyAdmissionQueueBlockedReasons: ["tenant_active_run_limit", "project_active_workspace", "persisted_running_run"],
    serverConcurrencyAdmissionRunControlCrossServer: true,
    tenantConcurrencyAdmissionChecked: true,
    tenantConcurrencyAdmissionSchemaVersion: "loom-concurrency-admission/v1",
    tenantConcurrencyAdmissionRunWorkspaceIsolation: "project",
    tenantConcurrencyAdmissionActiveRunClaimScope: "project",
    controlPlaneWorkspaceBranchLeaseChecked: true,
    controlPlaneWorkspaceBranchLeaseProvider: "agent-git-service",
    controlPlaneWorkspaceBranchLeaseIsolation: "project",
    controlPlaneWorkspaceBranchLeaseBranchDerivation: "run-suffixed",
    controlPlaneWorkspaceBranchLeaseActiveRunLeaseEvidence: true,
    multiAgentConcurrencyChecked: false,
    agentGitServiceCutoverChecked: true,
    agentGitServiceCutoverReceiptSecretAbsent: true,
    agentGitServiceCutoverWorkspaceTokenChecked: true,
  }), "utf8");

  const missingResult = await execa(
    "npx",
    [
      "tsx",
      "src/index.ts",
      "harness",
      "platform-concurrency-audit",
      "--cutover-report",
      cutoverPath,
      "--smoke-report",
      smokePath,
      "--require-agent-git-service",
      "--report",
      reportPath,
    ],
    { cwd: process.cwd(), reject: false, timeout: 5000 },
  );

  assert.equal(missingResult.exitCode, 1, missingResult.stderr);
  const missingBody = JSON.parse(missingResult.stdout);
  assert.equal(missingBody.schemaVersion, "platform-concurrency-audit/v1");
  assert.equal(missingBody.ok, false);
  assert.equal(missingBody.tokenFree, true);
  assert.equal(missingBody.controlPlaneProvider, "agent-git-service");
  assert.equal(missingBody.gates.cutoverConcurrencyOk, true);
  assert.equal(missingBody.gates.smokeConcurrencyOk, true);
  assert.equal(missingBody.gates.runScopedWorkspaces, false);
  assert.equal(missingBody.gates.workspaceBranchLeaseOk, false);
  assert.equal(missingBody.gates.multiAgentSmokeOk, false);
  assert.equal(missingBody.gates.agentGitServiceCutoverOk, true);
  assert.equal(missingBody.gates.agentGitServiceNativeProjectionOk, false);
  assert.ok(missingBody.missing.includes("runWorkspaceIsolation.run"));
  assert.ok(missingBody.missing.includes("smoke.multiAgentConcurrencyChecked"));
  assert.ok(missingBody.missing.includes("agentGitService.nativeProjection"));
  assert.ok(missingBody.nextActions.includes("Start serve with --executor-worktree-cwd <path-template> so runWorkspaceIsolation is run."));
  assert.deepEqual(JSON.parse(await readFile(reportPath, "utf8")), missingBody);

  await writeFile(cutoverPath, JSON.stringify({
    ...JSON.parse(await readFile(cutoverPath, "utf8")),
    serverConcurrencyAdmissionRunWorkspaceIsolation: "run",
    serverConcurrencyAdmissionActiveRunClaimScope: "run",
    tenantConcurrencyAdmissionRunWorkspaceIsolation: "run",
    tenantConcurrencyAdmissionActiveRunClaimScope: "run",
  }), "utf8");
  await writeFile(smokePath, JSON.stringify({
    ...JSON.parse(await readFile(smokePath, "utf8")),
    serverConcurrencyAdmissionRunWorkspaceIsolation: "run",
    serverConcurrencyAdmissionActiveRunClaimScope: "run",
    tenantConcurrencyAdmissionRunWorkspaceIsolation: "run",
    tenantConcurrencyAdmissionActiveRunClaimScope: "run",
    controlPlaneWorkspaceBranchLeaseIsolation: "run",
    multiAgentConcurrencyChecked: true,
    multiAgentConcurrencyIsolation: "run",
    multiAgentConcurrencyActiveRunLeaseChecked: true,
    multiAgentConcurrencyRunScopedFileWriteChecked: true,
    multiAgentConcurrencyRunScopedPrHandoffChecked: true,
    multiAgentConcurrencyBranch: "loom/run-123/handoff",
    agentGitServiceNativeProjectionChecked: true,
  }), "utf8");

  const readyResult = await execa(
    "npx",
    [
      "tsx",
      "src/index.ts",
      "harness",
      "platform-concurrency-audit",
      "--cutover-report",
      cutoverPath,
      "--smoke-report",
      smokePath,
      "--require-agent-git-service",
    ],
    { cwd: process.cwd(), reject: false, timeout: 5000 },
  );

  assert.equal(readyResult.exitCode, 0, readyResult.stderr);
  const readyBody = JSON.parse(readyResult.stdout);
  assert.equal(readyBody.ok, true);
  assert.deepEqual(readyBody.missing, []);
  assert.deepEqual(readyBody.nextActions, []);
  assert.equal(readyBody.strategy.workspaceLeaseScope, "run");
  assert.equal(readyBody.strategy.agentGitServiceRole, "provider-adapter");
});

