  assert.equal(mismatchedCiHandoff.exitCode, 1);
  const mismatchedCiHandoffBody = JSON.parse(mismatchedCiHandoff.stdout);
  assert.equal(mismatchedCiHandoffBody.ok, false);
  assert.equal(mismatchedCiHandoffBody.gates.ciRunProofOk, true);
  assert.equal(mismatchedCiHandoffBody.gates.ciRunProofAnchorOk, true);
  assert.equal(mismatchedCiHandoffBody.gates.ciRunProofStagingProofAnchorOk, false);
  assert.equal(mismatchedCiHandoffBody.gates.ciRunProofHandoffOk, false);
