test("loom harness platform-cutover-run executes only non-approval stages by default", async () => {
  const root = await tempDir("loom-cli-platform-cutover-run-default");
  const planPath = join(root, "plan.json");
  const logPath = join(root, "runner.log");
  const reportPath = join(root, "reports", "safe-run.json");
  await writeFile(planPath, JSON.stringify({
    stages: [
      cutoverRunnerStage("platform-preflight", "read-only", false, "preflight"),
      cutoverRunnerStage("serve", "long-running", true, "serve", "serve-running"),
      cutoverRunnerStage("agent-git-service-provisioning-plan-dry-run", "dry-run", false, "dry-run"),
      cutoverRunnerStage("agent-git-service-provisioning-plan-apply", "mutating", true, "apply", "ags-approval"),
    ],
  }), "utf8");

  const result = await execa(
    "npx",
    ["tsx", "src/index.ts", "harness", "platform-cutover-run", "--plan", planPath, "--report", reportPath],
    {
      cwd: process.cwd(),
      env: { ...process.env, LOOM_CUTOVER_RUN_LOG: logPath },
      reject: false,
    },
  );

  assert.equal(result.exitCode, 0, result.stderr || result.stdout);
  const body = JSON.parse(result.stdout);
  assert.equal(body.ok, true);
  assert.equal(body.reportPath, reportPath);
  assert.deepEqual(body.executed.map((stage: any) => stage.id), [
    "platform-preflight",
    "agent-git-service-provisioning-plan-dry-run",
  ]);
  assert.deepEqual(body.skipped.map((stage: any) => ({ id: stage.id, reason: stage.reason, blocking: stage.blocking })), [
    { id: "serve", reason: "approvalRequired", blocking: false },
    { id: "agent-git-service-provisioning-plan-apply", reason: "approvalRequired", blocking: false },
  ]);
  assert.deepEqual((await readFile(logPath, "utf8")).trim().split("\n"), ["preflight", "dry-run"]);
  assert.deepEqual(JSON.parse(await readFile(reportPath, "utf8")), body);
});

