test("loom harness platform-cutover-run blocks stages until external requirements are satisfied", async () => {
  const root = await tempDir("loom-cli-platform-cutover-run-requires");
  const planPath = join(root, "plan.json");
  const blockedLogPath = join(root, "blocked.log");
  const satisfiedLogPath = join(root, "satisfied.log");
  await writeFile(planPath, JSON.stringify({
    stages: [
      cutoverRunnerStage("platform-preflight", "read-only", false, "preflight"),
      cutoverRunnerStage("cutover-report", "read-only", false, "cutover-report", undefined, ["serve-running"]),
    ],
  }), "utf8");

  const blocked = await execa(
    "npx",
    ["tsx", "src/index.ts", "harness", "platform-cutover-run", "--plan", planPath],
    {
      cwd: process.cwd(),
      env: { ...process.env, LOOM_CUTOVER_RUN_LOG: blockedLogPath },
      reject: false,
    },
  );

  assert.equal(blocked.exitCode, 1);
  const blockedBody = JSON.parse(blocked.stdout);
  assert.equal(blockedBody.ok, false);
  assert.deepEqual(blockedBody.satisfiedRequirements, ["platform-preflight"]);
  assert.deepEqual(blockedBody.executed.map((stage: any) => stage.id), ["platform-preflight"]);
  assert.deepEqual(blockedBody.skipped, [
    {
      id: "cutover-report",
      command: "loom harness cutover-report",
      reason: "unmetRequirement",
      blocking: true,
      missingRequirements: ["serve-running"],
    },
  ]);
  assert.deepEqual((await readFile(blockedLogPath, "utf8")).trim().split("\n"), ["preflight"]);

  const satisfied = await execa(
    "npx",
    [
      "tsx",
      "src/index.ts",
      "harness",
      "platform-cutover-run",
      "--plan",
      planPath,
      "--satisfy",
      "serve-running",
    ],
    {
      cwd: process.cwd(),
      env: { ...process.env, LOOM_CUTOVER_RUN_LOG: satisfiedLogPath },
      reject: false,
    },
  );

  assert.equal(satisfied.exitCode, 0, satisfied.stderr || satisfied.stdout);
  const satisfiedBody = JSON.parse(satisfied.stdout);
  assert.equal(satisfiedBody.ok, true);
  assert.deepEqual(satisfiedBody.satisfiedRequirements, ["serve-running", "platform-preflight", "cutover-report"]);
  assert.deepEqual(satisfiedBody.executed.map((stage: any) => stage.id), ["platform-preflight", "cutover-report"]);
  assert.deepEqual(satisfiedBody.skipped, []);
  assert.deepEqual((await readFile(satisfiedLogPath, "utf8")).trim().split("\n"), ["preflight", "cutover-report"]);
});

test("loom harness platform-cutover-run can block selected stages on missing env without leaking values", async () => {
  const root = await tempDir("loom-cli-platform-cutover-run-env-check");
  const planPath = join(root, "plan.json");
  const logPath = join(root, "runner.log");
  const reportPath = join(root, "reports", "run.json");
  await writeFile(planPath, JSON.stringify({
    externalEnvironment: {
      tokenFree: true,
      requiredVariables: [
        {
          name: "LOOM_RUN_ENV_PRESENT",
          requiredFor: ["platform-preflight"],
          uses: [{ sourceFlag: "--model-key-env", purpose: "model gateway key" }],
        },
        {
          name: "LOOM_RUN_ENV_MISSING",
          requiredFor: ["platform-preflight"],
          uses: [{ sourceFlag: "--tenant-key-env", purpose: "tenant API key", tenant: "alice", actor: "dev", role: "developer" }],
        },
      ],
    },
    stages: [
      cutoverRunnerStage("platform-preflight", "read-only", false, "preflight"),
    ],
  }), "utf8");

  const blocked = await execa(
    "npx",
    [
      "tsx",
      "src/index.ts",
      "harness",
      "platform-cutover-run",
      "--plan",
      planPath,
      "--stage",
      "platform-preflight",
      "--check-env",
      "--report",
      reportPath,
    ],
    {
      cwd: process.cwd(),
      env: { ...process.env, LOOM_RUN_ENV_PRESENT: "present-run-secret" },
      reject: false,
    },
  );

  assert.equal(blocked.exitCode, 1);
  assert.equal(blocked.stdout.includes("present-run-secret"), false);
  const blockedBody = JSON.parse(blocked.stdout);
  assert.equal(blockedBody.ok, false);
  assert.deepEqual(blockedBody.executed, []);
  assert.deepEqual(blockedBody.environment?.checkedVariableNames, ["LOOM_RUN_ENV_PRESENT", "LOOM_RUN_ENV_MISSING"]);
  assert.deepEqual(blockedBody.environment?.missing.map((entry: any) => entry.name), ["LOOM_RUN_ENV_MISSING"]);
  assert.deepEqual(blockedBody.skipped, [
    {
      id: "platform-preflight",
      command: "loom harness platform-preflight",
      reason: "missingEnvironment",
      blocking: true,
      missingEnvironmentVariables: [
        {
          name: "LOOM_RUN_ENV_MISSING",
          requiredFor: ["platform-preflight"],
          uses: [{ sourceFlag: "--tenant-key-env", purpose: "tenant API key", tenant: "alice", actor: "dev", role: "developer" }],
        },
      ],
    },
  ]);
  assert.rejects(() => readFile(logPath, "utf8"), /ENOENT/);
  assert.deepEqual(JSON.parse(await readFile(reportPath, "utf8")), blockedBody);

  const ready = await execa(
    "npx",
    [
      "tsx",
      "src/index.ts",
      "harness",
      "platform-cutover-run",
      "--plan",
      planPath,
      "--stage",
      "platform-preflight",
      "--check-env",
    ],
    {
      cwd: process.cwd(),
      env: {
        ...process.env,
        LOOM_CUTOVER_RUN_LOG: logPath,
        LOOM_RUN_ENV_PRESENT: "present-run-secret",
        LOOM_RUN_ENV_MISSING: "missing-now-present-run-secret",
      },
      reject: false,
    },
  );

  assert.equal(ready.exitCode, 0, ready.stderr || ready.stdout);
  assert.equal(ready.stdout.includes("present-run-secret"), false);
  assert.equal(ready.stdout.includes("missing-now-present-run-secret"), false);
  const readyBody = JSON.parse(ready.stdout);
  assert.equal(readyBody.ok, true);
  assert.deepEqual(readyBody.environment?.missing, []);
  assert.deepEqual(readyBody.executed.map((stage: any) => stage.id), ["platform-preflight"]);
  assert.equal((await readFile(logPath, "utf8")).trim(), "preflight");
});

