test("loom harness platform-cutover-env-check validates required env names without leaking values", async () => {
  const root = await tempDir("loom-cli-platform-cutover-env-check");
  const planPath = join(root, "plan.json");
  const reportPath = join(root, "reports", "env-check.json");
  await writeFile(planPath, JSON.stringify({
    externalEnvironment: {
      tokenFree: true,
      requiredVariables: [
        {
          name: "LOOM_CUTOVER_IGNORED",
          requiredFor: ["platform-preflight"],
          uses: [{ sourceFlag: "--model-key-env", purpose: "ignored for smoke" }],
        },
        {
          name: "LOOM_CUTOVER_PRESENT",
          requiredFor: ["smoke"],
          uses: [{ sourceFlag: "--token-env", purpose: "developer tenant API token", tenant: "alice" }],
        },
        {
          name: "LOOM_CUTOVER_MISSING",
          requiredFor: ["serve", "smoke"],
          uses: [{ sourceFlag: "--control-plane-token-env", purpose: "control-plane token" }],
        },
      ],
    },
  }), "utf8");

  const missing = await execa(
    "npx",
    [
      "tsx",
      "src/index.ts",
      "harness",
      "platform-cutover-env-check",
      "--plan",
      planPath,
      "--stage",
      "smoke",
      "--report",
      reportPath,
    ],
    {
      cwd: process.cwd(),
      env: {
        ...process.env,
        LOOM_CUTOVER_PRESENT: "present-secret-value",
        LOOM_CUTOVER_IGNORED: "ignored-secret-value",
      },
      reject: false,
    },
  );

  assert.equal(missing.exitCode, 1);
  assert.equal(missing.stdout.includes("present-secret-value"), false);
  assert.equal(missing.stdout.includes("ignored-secret-value"), false);
  const missingBody = JSON.parse(missing.stdout);
  assert.equal(missingBody.ok, false);
  assert.equal(missingBody.tokenFree, true);
  assert.deepEqual(missingBody.checkedStageIds, ["smoke"]);
  assert.deepEqual(missingBody.checkedVariableNames, ["LOOM_CUTOVER_PRESENT", "LOOM_CUTOVER_MISSING"]);
  assert.deepEqual(missingBody.present.map((entry: any) => entry.name), ["LOOM_CUTOVER_PRESENT"]);
  assert.deepEqual(missingBody.missing.map((entry: any) => entry.name), ["LOOM_CUTOVER_MISSING"]);
  assert.deepEqual(JSON.parse(await readFile(reportPath, "utf8")), missingBody);
  assert.equal((await readFile(reportPath, "utf8")).includes("present-secret-value"), false);

  const ready = await execa(
    "npx",
    [
      "tsx",
      "src/index.ts",
      "harness",
      "platform-cutover-env-check",
      "--plan",
      planPath,
      "--stage",
      "smoke",
    ],
    {
      cwd: process.cwd(),
      env: {
        ...process.env,
        LOOM_CUTOVER_PRESENT: "present-secret-value",
        LOOM_CUTOVER_MISSING: "missing-now-present-secret",
      },
      reject: false,
    },
  );

  assert.equal(ready.exitCode, 0, ready.stderr || ready.stdout);
  assert.equal(ready.stdout.includes("present-secret-value"), false);
  assert.equal(ready.stdout.includes("missing-now-present-secret"), false);
  const readyBody = JSON.parse(ready.stdout);
  assert.equal(readyBody.ok, true);
  assert.deepEqual(readyBody.missing, []);
  assert.deepEqual(readyBody.present.map((entry: any) => entry.name), ["LOOM_CUTOVER_PRESENT", "LOOM_CUTOVER_MISSING"]);
});

