test("loom harness platform-staging-run executes strict external pre-serve staging", async () => {
  const root = await tempDir("loom-cli-platform-staging-run");
  const scriptPath = join(root, "write-staging-report.mjs");
  const sourcePlanPath = join(root, "plan.json");
  const outDir = join(root, "bundle");
  const reportPath = join(outDir, "reports", "staging-run.json");
  await writeFile(scriptPath, [
    "import { mkdirSync, writeFileSync } from 'node:fs';",
    "import { join } from 'node:path';",
    "const name = process.argv[2];",
    "mkdirSync('reports', { recursive: true });",
    "const reports = {",
    "  'platform-preflight.json': { schemaVersion: 'platform-preflight/v1', ok: true, tokenFree: true, missing: [], gates: { doctor: true, model: true, controlPlane: true, coder: true }, nextCommandsReady: true, model: { ok: true, baseUrl: 'https://litellm.staging.acme.dev/v1', checks: { apiKey: { ok: true, required: true }, chatCompletion: { ok: true, required: true }, agentStep: { ok: true, required: true }, modelUsage: { ok: true, required: true } }, modelUsage: { model: 'platform-model', promptTokens: 8, completionTokens: 4, totalTokens: 12, costUsd: 0.001 } }, coder: { ok: true, executor: { kind: 'coder' }, checks: { configuration: { ok: true, required: true }, prepare: { ok: true, required: true }, remoteCommand: { ok: true, required: true, output: 'loom-coder-preflight-ok' }, browserUrls: { ok: true, required: true, ideUrl: 'https://coder.staging.acme.dev/@alice/vas', previewUrl: 'https://preview.staging.acme.dev/vas' } } }, controlPlane: { ok: true, provider: 'agent-git-service', baseUrl: 'https://ags.staging.acme.dev/api/v3', compatibilityReport: { ok: true } } },",
    "  'agent-git-service-staging-readiness.json': { schemaVersion: 'agent-git-service-staging-readiness/v1', ok: true, tokenFree: true, provider: 'agent-git-service', baseUrl: 'https://ags.staging.acme.dev/api/v3', issue: 'octo/real-smoke#42', repo: 'octo/real-smoke', serverReadiness: { ok: true, url: 'https://ags.staging.acme.dev/readyz', httpStatus: 200, status: 'ready', version: 'contract', checkNames: ['main_db'] }, wikiMemory: { ok: true, page: 'vas/staging' }, missing: [], gates: { token: true, serverReadiness: true, discovery: true, issueWorkspaces: true, issueComments: true, wikiMemory: true } },",
    "};",
    "if (!reports[name]) throw new Error(`unknown report ${name}`);",
    "writeFileSync(join('reports', name), `${JSON.stringify(reports[name], null, 2)}\\n`, 'utf8');",
  ].join("\n"), "utf8");
  const plan = {
    ok: true,
    profile: "platform-readiness",
    tenant: "alice",
    project: "vas",
    serverUrl: "https://loom.staging.acme.dev",
    controlPlaneProvider: "agent-git-service",
    externalEnvironment: {
      systems: {
        modelGateway: { baseUrl: "https://litellm.staging.acme.dev/v1" },
        executor: { kind: "coder" },
        controlPlane: { provider: "agent-git-service", baseUrl: "https://ags.staging.acme.dev/api/v3" },
        agentGitServiceStaging: {
          issue: "octo/real-smoke#42",
          repo: "octo/real-smoke",
          wikiPage: "vas/staging",
        },
      },
      requiredVariables: [
        {
          name: "LOOM_EXTERNAL_STAGING_SECRET",
          requiredFor: ["platform-preflight", "agent-git-service-staging-readiness"],
          uses: [{ sourceFlag: "--token-env", purpose: "external staging test secret" }],
        },
      ],
    },
    stages: [
      {
        id: "platform-preflight",
        command: "loom harness platform-preflight",
        commandArgs: ["node", scriptPath, "platform-preflight.json"],
        executionMode: "read-only",
        approvalRequired: false,
        tokenFree: true,
      },
      {
        id: "agent-git-service-staging-readiness",
        command: "loom harness agent-git-service-staging-readiness",
        commandArgs: ["node", scriptPath, "agent-git-service-staging-readiness.json"],
        executionMode: "read-only",
        approvalRequired: false,
        tokenFree: true,
      },
      {
        id: "serve",
        command: "loom harness serve",
        commandArgs: ["loom", "harness", "serve"],
        executionMode: "long-running",
        approvalRequired: true,
        tokenFree: true,
        operatorGate: {
          id: "serve-running",
          evidence: "external serve is reachable",
        },
      },
    ],
  };
  await writeFile(sourcePlanPath, `${JSON.stringify(plan, null, 2)}\n`, "utf8");

  const bundle = await execa(
    "npx",
    ["tsx", "src/index.ts", "harness", "platform-cutover-bundle", "--plan", sourcePlanPath, "--out", outDir],
    { cwd: process.cwd(), reject: false },
  );
  assert.equal(bundle.exitCode, 0, bundle.stderr || bundle.stdout);

  const result = await execa(
    "npx",
    [
      "tsx",
      "src/index.ts",
      "harness",
      "platform-staging-run",
      "--dir",
      outDir,
      "--require-external-staging",
      "--report",
      reportPath,
      "--forbid-env",
      "LOOM_EXTERNAL_STAGING_SECRET",
    ],
    {
      cwd: process.cwd(),
      env: { ...process.env, LOOM_EXTERNAL_STAGING_SECRET: "external-secret-value" },
      reject: false,
    },
  );

  assert.equal(result.exitCode, 0, result.stderr || result.stdout);
  assert.equal(result.stdout.includes("external-secret-value"), false);
  const body = JSON.parse(result.stdout);
  assert.equal(body.schemaVersion, "platform-staging-run/v1");
  assert.equal(body.ok, true);
  assert.equal(body.tokenFree, true);
  assert.equal(body.phase, "pre-serve");
  assert.equal(body.requireExternalStaging, true);
  assert.deepEqual(body.selectedStageIds, ["platform-preflight", "agent-git-service-staging-readiness"]);
  assert.deepEqual(body.missing, []);
  assert.deepEqual(body.forbiddenValueHitReports, []);
  assert.deepEqual(body.gates, {
    bundleVerifyOk: true,
    environmentOk: true,
    preServeStagesOk: true,
    externalStagingReady: true,
    stagingEvidenceOk: true,
    stagingVerdictReady: true,
    readyForServe: true,
  });
  assert.equal(body.reports.bundleVerify.name, "bundle-verify.json");
  assert.equal(body.reports.stageRuns.length, 2);
  assert.equal(body.reports.stagingTargets.name, "staging-targets.json");
  assert.equal(body.reports.stagingEvidence.ok, true);
  assert.equal(body.reports.stagingVerdict.ok, true);
  assert.equal(JSON.parse(await readFile(join(outDir, "reports", "staging-verdict.json"), "utf8")).decision, "ready-for-serve");
  await assert.rejects(() => readFile(join(outDir, "reports", "operator-artifacts.json"), "utf8"), /ENOENT/);
  assert.deepEqual(JSON.parse(await readFile(reportPath, "utf8")), body);

  await writeFile(join(outDir, "reports", "platform-preflight.json"), `${JSON.stringify({
    schemaVersion: "platform-preflight/v1",
    ok: true,
    tokenFree: true,
    missing: [],
    gates: {
      doctor: true,
      model: true,
      controlPlane: true,
      coder: true,
    },
    model: modelPreflightFixture("http://127.0.0.1:4000"),
    coder: { ...coderPreflightFixture(), executor: { kind: "local" } },
    controlPlane: {
      ok: true,
      provider: "agent-git-service",
      baseUrl: "http://localhost:3000/api/v3",
      compatibilityReport: { ok: true },
    },
    nextCommandsReady: true,
  }, null, 2)}\n`, "utf8");
  const mismatchedPreflight = await execa(
    "npx",
    [
      "tsx",
      "src/index.ts",
      "harness",
      "platform-cutover-artifacts-verify",
      "--dir",
      outDir,
      "--plan",
      join(outDir, "plan.json"),
      "--require-external-staging",
    ],
    { cwd: process.cwd(), reject: false },
  );
  assert.equal(mismatchedPreflight.exitCode, 1);
  const mismatchedPreflightBody = JSON.parse(mismatchedPreflight.stdout);
  assert.equal(mismatchedPreflightBody.ok, false);
  assert.deepEqual(mismatchedPreflightBody.preServeEvidenceMissing, [
    "platformPreflight.model.external",
    "platformPreflight.coder.executor",
    "platformPreflight.controlPlane.agentGitServiceExternal",
  ]);
});

