test("loom harness platform-operator-status surfaces missing AGS native write proof during post-serve", async () => {
  const root = await tempDir("loom-cli-platform-operator-status-ags-native-write");
  const outDir = join(root, "cutover-bundle");
  const reportDir = join(outDir, "reports");
  const reportPath = join(reportDir, "operator-status.json");
  const nativeWriteCommandArgs = [
    "loom",
    "harness",
    "agent-git-service-native-write-check",
    "--control-plane-url",
    "https://ags.example/api/v3",
    "--control-plane-token-env",
    "LOOM_TEST_AGS_TOKEN",
    "--issue",
    "octo/real-smoke#42",
    "--repo",
    "octo/real-smoke",
    "--workspace-id",
    "ws-real-smoke",
    "--attachment-url",
    "https://evidence.example/native-write.json",
    "--wiki-page",
    "vas/staging",
    "--wiki-note",
    "loom native write check for staging",
    "--approve-mutating",
    "--report",
    "reports/agent-git-service-native-write-check.json",
  ];
  await mkdir(reportDir, { recursive: true });
  await writeFile(join(outDir, "plan.json"), `${JSON.stringify({
    stages: [
      {
        id: "agent-git-service-native-write-check",
        command: "loom harness agent-git-service-native-write-check",
        commandArgs: nativeWriteCommandArgs,
        executionMode: "mutating",
        approvalRequired: true,
        tokenFree: true,
        requires: ["serve-running", "external-change-window"],
        operatorGate: {
          id: "agent-git-service-native-write-approval",
          evidence: "operator approves AGS native write check",
        },
      },
    ],
  }, null, 2)}\n`, "utf8");
  await writeFile(join(outDir, "github-actions-staging.yml"), [
    "name: Loom Strict External Staging",
    "on:",
    "  workflow_dispatch:",
    "concurrency:",
    "  group: loom-strict-staging-${{ github.ref }}-${{ inputs.phase }}",
    "  cancel-in-progress: false",
    "",
  ].join("\n"), "utf8");
  await writeFile(join(outDir, "external-secrets.json"), `${JSON.stringify({
    schemaVersion: "platform-external-secrets/v1",
    tokenFree: true,
    providerHint: "ci-secret-store",
    requiredEnv: [],
  }, null, 2)}\n`, "utf8");
  await writeFile(join(outDir, "staging-ci.json"), `${JSON.stringify({
    schemaVersion: "platform-staging-ci/v1",
    tokenFree: true,
    commands: {
      postServe: "LOOM_CUTOVER_PHASE=post-serve ./commands.sh",
    },
  }, null, 2)}\n`, "utf8");
  await writeFile(join(reportDir, "external-staging-audit.json"), `${JSON.stringify({
    schemaVersion: "platform-external-staging-audit/v1",
    ok: true,
    tokenFree: true,
    missing: [],
    gates: {
      bundleOk: true,
      environmentOk: true,
      externalTargetsReady: true,
      stagingPrerequisitesOk: true,
      preServeEvidenceOk: true,
      stagingRunReady: true,
      stagingVerdictReady: true,
    },
  }, null, 2)}\n`, "utf8");
  await writeFile(join(reportDir, "staging-verdict.json"), `${JSON.stringify({
    schemaVersion: "platform-staging-verdict/v1",
    ok: true,
    tokenFree: true,
    decision: "ready-for-serve",
    missing: [],
    failedGates: [],
  }, null, 2)}\n`, "utf8");
  await writeFile(join(reportDir, "serve-ready.json"), `${JSON.stringify({
    schemaVersion: "platform-serve-ready/v1",
    ok: true,
    tokenFree: true,
  }, null, 2)}\n`, "utf8");

  const status = await execa(
    "npx",
    [
      "tsx",
      "src/index.ts",
      "harness",
      "platform-operator-status",
      "--dir",
      outDir,
      "--require-agent-git-service",
      "--report",
      reportPath,
    ],
    { cwd: process.cwd(), reject: false },
  );

  assert.equal(status.exitCode, 1);
  const body = JSON.parse(status.stdout);
  assert.equal(body.phase, "run-post-serve-proof");
  assert.equal(body.agentGitService.reports.nativeWriteCheck.name, "agent-git-service-native-write-check.json");
  assert.equal(body.agentGitService.reports.nativeWriteCheck.exists, false);
  assert.equal(body.agentGitService.gates.nativeWriteCheckOk, false);
  assert.ok(body.agentGitService.missing.includes("agentGitService.nativeWriteCheck"));
  assert.ok(body.agentGitService.nextActions.includes("Run AGS native write check from the operator bundle, then rerun platform-operator-status."));
  const postServeProof = body.blockingGroups.find((group: { id: string }) => group.id === "post-serve-proof");
  assert.ok(postServeProof);
  assert.ok(postServeProof.missing.includes("reports.agentGitServiceNativeWriteCheck"));
  const postServeStep = body.cockpitPlan.steps.find((step: { id: string }) => step.id === "post-serve-proof");
  assert.equal(postServeStep.commandRefs[0].label, "agent-git-service-native-write-check");
  assert.deepEqual(postServeStep.commandRefs[0].commandArgs, nativeWriteCommandArgs);
  assert.equal(postServeStep.commandRefs[1].label, "ags-evidence-sync");
  assert.equal(postServeStep.commandRefs[2].label, "ags-evidence-import");
  assert.deepEqual(postServeProof.commandRefs.find((ref: { label: string }) => ref.label === "ags-evidence-sync"), {
    label: "ags-evidence-sync",
    command: `loom harness platform-operator-ags-evidence-sync --dir ${outDir} --run-id '<github-run-id>' --phase post-serve --require-agent-git-service --report ${join(reportDir, "ags-evidence-sync.json")}`,
    commandArgs: ["loom", "harness", "platform-operator-ags-evidence-sync", "--dir", outDir, "--run-id", "<github-run-id>", "--phase", "post-serve", "--require-agent-git-service", "--report", join(reportDir, "ags-evidence-sync.json")],
  });
  assert.deepEqual(postServeProof.commandRefs.find((ref: { label: string }) => ref.label === "ags-evidence-import"), {
    label: "ags-evidence-import",
    command: `loom harness platform-operator-ags-evidence-import --dir ${outDir} --artifact-dir '<downloaded-ags-artifact-dir>' --phase post-serve --require-agent-git-service --report ${join(reportDir, "ags-evidence-import.json")}`,
    commandArgs: ["loom", "harness", "platform-operator-ags-evidence-import", "--dir", outDir, "--artifact-dir", "<downloaded-ags-artifact-dir>", "--phase", "post-serve", "--require-agent-git-service", "--report", join(reportDir, "ags-evidence-import.json")],
  });
  assert.deepEqual(postServeProof.commandRefs.find((ref: { label: string }) => ref.label === "agent-git-service-native-write-check"), {
    label: "agent-git-service-native-write-check",
    command: "loom harness agent-git-service-native-write-check --control-plane-url https://ags.example/api/v3 --control-plane-token-env LOOM_TEST_AGS_TOKEN --issue 'octo/real-smoke#42' --repo octo/real-smoke --workspace-id ws-real-smoke --attachment-url https://evidence.example/native-write.json --wiki-page vas/staging --wiki-note 'loom native write check for staging' --approve-mutating --report reports/agent-git-service-native-write-check.json",
    commandArgs: nativeWriteCommandArgs,
  });
  assert.deepEqual(JSON.parse(await readFile(reportPath, "utf8")), body);
});

