        commandArgs: ["loom", "harness", "agent-git-service-staging-readiness", "--control-plane-url", "https://ags.example/api/v3", "--control-plane-token-env", "LOOM_TEST_AGS_TOKEN", "--issue", "octo/real-smoke#42", "--repo", "octo/real-smoke", "--wiki-page", "vas/staging", "--report", "reports/agent-git-service-staging-readiness.json"],
