    assert.equal(audit.at(-1).data.ok, false);
    assert.equal(audit.at(-1).data.phase, "prepare-pre-serve");
    assert.equal(audit.at(-1).data.missingInputCount, body.handoff.missingInputCount);
    assert.equal(audit.at(-1).data.commandRefCount, body.handoff.commandRefCount);
    assert.deepEqual(audit.at(-1).data.githubTarget, { repo: "team/loom", ref: "main" });
