    assert.deepEqual(JSON.parse(await readFile(join(reportDir, "agent-git-service-staging-readiness.json"), "utf8")), stagingReadiness);
    assert.deepEqual(JSON.parse(await readFile(join(reportDir, "agent-git-service-compat", "candidate.json"), "utf8")), candidate);
