test("harness server recovers persisted operator cockpit execution queue after restart", async () => {
  const workspaceRoot = await tempDir("loom-cli-platform-operator-cockpit-execution-queue-recovery");
  const outDir = join(workspaceRoot, "cutover-bundle");
  const reportDir = join(outDir, "reports");
  const lockDir = join(outDir, ".loom");
  const queueDir = join(lockDir, "operator-cockpit-queue");
  const lockPath = join(lockDir, "operator-cockpit-runner.lock");
  const queueId = "recovered-operator-cockpit-queue";
  const queueFilePath = join(queueDir, `${queueId}.json`);
  const markerPath = join(outDir, "recovered-queued-marker.txt");
  const commandArgs = [
    process.execPath,
    "-e",
    `require("node:fs").writeFileSync(${JSON.stringify(markerPath)}, "recovered-queued-executed\\n")`,
  ];
  await mkdir(reportDir, { recursive: true });
  await mkdir(queueDir, { recursive: true });
  await writeFile(lockPath, `${JSON.stringify({
    schemaVersion: "platform-operator-cockpit-runner-lock/v1",
    tokenFree: true,
    owner: "operator-cockpit-runner:active",
    commandLabel: "write-recovered-queued-marker",
    currentStepId: "pre-serve-evidence",
    currentBlockingGroupId: "pre-serve-evidence",
    acquiredAt: new Date().toISOString(),
    expiresAt: new Date(Date.now() + 30 * 60 * 1000).toISOString(),
    ttlMs: 1_800_000,
  }, null, 2)}\n`, "utf8");
  await writeFile(join(reportDir, "operator-cockpit-next.json"), `${JSON.stringify({
    schemaVersion: "platform-operator-cockpit-next/v1",
    tokenFree: true,
    phase: "ready-for-serve",
    state: "ready-to-run",
    pendingStepCount: 1,
    missingInputCount: 0,
    commandRefCount: 1,
    currentStepId: "pre-serve-evidence",
    currentBlockingGroupId: "pre-serve-evidence",
    currentStepMissingInputCount: 0,
    commandRef: {
      label: "write-recovered-queued-marker",
      command: commandArgs.join(" "),
      commandArgs,
    },
  }, null, 2)}\n`, "utf8");
  await writeFile(queueFilePath, `${JSON.stringify({
    schemaVersion: "platform-operator-cockpit-loop-queue-item/v1",
    tokenFree: true,
    queueId,
    tenant: "alice",
    dir: outDir,
    enqueuedAt: "2026-07-09T00:00:00.000Z",
    status: "queued",
    clientId: "cockpit-ui",
    ciTarget: {},
    maxSteps: 1,
  }, null, 2)}\n`, "utf8");
  await writeFile(join(queueDir, "bad-operator-cockpit-queue.json"), `${JSON.stringify({
    schemaVersion: "platform-operator-cockpit-loop-queue-item/v1",
    tokenFree: true,
    queueId: "bad-operator-cockpit-queue",
    tenant: "alice",
    dir: outDir,
    enqueuedAt: "2026-07-09T00:00:00.000Z",
    status: "queued",
    clientId: "bad\nclient",
    ciTarget: {},
    maxSteps: 1,
  }, null, 2)}\n`, "utf8");

  const server = createHarnessHttpServer({
    workspaceRoot,
    allowUnsafeLocalExecutor: true,
    allowedTools: onlineSandboxTools(),
    tenantApiKeys: tenantRoleKeys(),
    operatorBundleDir: outDir,
  });
  await new Promise<void>((resolve) => server.listen(0, "127.0.0.1", resolve));
  const address = server.address();
  assert.equal(typeof address, "object");
  assert.ok(address);

  try {
    const statusUrl = `http://127.0.0.1:${address.port}/tenants/alice/operator/cockpit-execution-status`;
    const recoveredStatus = await pollOperatorCockpitExecutionStatus(statusUrl, (body) =>
      body.queue.length === 1 && body.queue[0].queueId === queueId,
    );
    assert.equal(recoveredStatus.queue[0].status, "queued");
    assert.equal(recoveredStatus.queue[0].queuePosition, 1);
    assert.equal(recoveredStatus.queue[0].clientId, "cockpit-ui");
    await assert.rejects(() => readFile(markerPath, "utf8"), /ENOENT/);

    await unlink(lockPath);
    const executedStatus = await pollOperatorCockpitExecutionStatus(statusUrl, (body) =>
      body.queue.length === 0 &&
      body.lastQueuedExecution?.queueId === queueId &&
      body.lastQueuedExecution?.status === "executed",
    );
    assert.equal(executedStatus.lastQueuedExecution.execution.mode, "executed");
    assert.equal(executedStatus.lastQueuedExecution.execution.ok, true);
    assert.equal(await readFile(markerPath, "utf8"), "recovered-queued-executed\n");
    await assert.rejects(() => readFile(queueFilePath, "utf8"), /ENOENT/);
  } finally {
    await new Promise<void>((resolve) => server.close(() => resolve()));
  }
});

test("harness server claims persisted operator cockpit queue across server instances", async () => {
  const workspaceRoot = await tempDir("loom-cli-platform-operator-cockpit-execution-queue-cross-instance");
  const outDir = join(workspaceRoot, "cutover-bundle");
  const reportDir = join(outDir, "reports");
  const lockDir = join(outDir, ".loom");
  const queueDir = join(lockDir, "operator-cockpit-queue");
  const lockPath = join(lockDir, "operator-cockpit-runner.lock");
  const queueId = "cross-instance-operator-cockpit-queue";
  const queueFilePath = join(queueDir, `${queueId}.json`);
  const claimFilePath = join(queueDir, `${queueId}.claim.json`);
  const markerPath = join(outDir, "cross-instance-marker.txt");
  const commandArgs = [
    process.execPath,
    "-e",
    [
      `require("node:fs").appendFileSync(${JSON.stringify(markerPath)}, "claimed-once\\n")`,
      "Atomics.wait(new Int32Array(new SharedArrayBuffer(4)), 0, 0, 1000)",
    ].join(";"),
  ];
  await mkdir(reportDir, { recursive: true });
  await mkdir(queueDir, { recursive: true });
  await writeFile(lockPath, `${JSON.stringify({
    schemaVersion: "platform-operator-cockpit-runner-lock/v1",
    tokenFree: true,
    owner: "operator-cockpit-runner:active",
    commandLabel: "write-cross-instance-marker",
    currentStepId: "pre-serve-evidence",
    currentBlockingGroupId: "pre-serve-evidence",
    acquiredAt: new Date().toISOString(),
    expiresAt: new Date(Date.now() + 30 * 60 * 1000).toISOString(),
    ttlMs: 1_800_000,
  }, null, 2)}\n`, "utf8");
  await writeFile(join(reportDir, "operator-cockpit-next.json"), `${JSON.stringify({
    schemaVersion: "platform-operator-cockpit-next/v1",
    tokenFree: true,
    phase: "ready-for-serve",
    state: "ready-to-run",
    pendingStepCount: 1,
    missingInputCount: 0,
    commandRefCount: 1,
    currentStepId: "pre-serve-evidence",
    currentBlockingGroupId: "pre-serve-evidence",
    currentStepMissingInputCount: 0,
    commandRef: {
      label: "write-cross-instance-marker",
      command: commandArgs.join(" "),
      commandArgs,
    },
  }, null, 2)}\n`, "utf8");
  await writeFile(queueFilePath, `${JSON.stringify({
    schemaVersion: "platform-operator-cockpit-loop-queue-item/v1",
    tokenFree: true,
    queueId,
    tenant: "alice",
    dir: outDir,
    enqueuedAt: "2026-07-09T00:00:00.000Z",
    status: "queued",
    clientId: "cockpit-ui",
    ciTarget: {},
    maxSteps: 1,
  }, null, 2)}\n`, "utf8");

  const serverA = createHarnessHttpServer({
    workspaceRoot,
    allowUnsafeLocalExecutor: true,
    allowedTools: onlineSandboxTools(),
    tenantApiKeys: tenantRoleKeys(),
    operatorBundleDir: outDir,
  });
  const serverB = createHarnessHttpServer({
    workspaceRoot,
    allowUnsafeLocalExecutor: true,
    allowedTools: onlineSandboxTools(),
    tenantApiKeys: tenantRoleKeys(),
    operatorBundleDir: outDir,
  });
  await Promise.all([
    new Promise<void>((resolve) => serverA.listen(0, "127.0.0.1", resolve)),
    new Promise<void>((resolve) => serverB.listen(0, "127.0.0.1", resolve)),
  ]);
  const addressA = serverA.address();
  const addressB = serverB.address();
  assert.equal(typeof addressA, "object");
  assert.equal(typeof addressB, "object");
  assert.ok(addressA);
  assert.ok(addressB);

  try {
    const statusUrlA = `http://127.0.0.1:${addressA.port}/tenants/alice/operator/cockpit-execution-status`;
    const statusUrlB = `http://127.0.0.1:${addressB.port}/tenants/alice/operator/cockpit-execution-status`;
    await pollOperatorCockpitExecutionStatus(statusUrlA, (body) => body.queue.length === 1 && body.queue[0].queueId === queueId);
    await pollOperatorCockpitExecutionStatus(statusUrlB, (body) => body.queue.length === 1 && body.queue[0].queueId === queueId);

    await unlink(lockPath);
    const claimDeadline = Date.now() + 8_000;
    while (Date.now() < claimDeadline) {
      try {
        await readFile(markerPath, "utf8");
        break;
      } catch {
        await new Promise((resolve) => setTimeout(resolve, 25));
      }
    }
    const claimFile = JSON.parse(await readFile(claimFilePath, "utf8"));
    assert.equal(claimFile.schemaVersion, "platform-operator-cockpit-loop-queue-claim/v1");
    assert.equal(claimFile.tokenFree, true);
    assert.equal(claimFile.queueId, queueId);
    assert.equal(claimFile.tenant, "alice");
    assert.equal(claimFile.dir, outDir);

    await pollOperatorCockpitExecutionStatus(statusUrlA, (body) =>
      body.queue.length === 0 ||
      body.lastQueuedExecution?.queueId === queueId,
      8_000,
    );
    await assert.rejects(() => readFile(queueFilePath, "utf8"), /ENOENT/);
    await assert.rejects(() => readFile(claimFilePath, "utf8"), /ENOENT/);
    await new Promise((resolve) => setTimeout(resolve, 600));

    const markerLines = (await readFile(markerPath, "utf8")).trim().split("\n");
    assert.deepEqual(markerLines, ["claimed-once"]);
    const finalStatusA = await fetch(statusUrlA, { headers: { authorization: "Bearer admin-key" } });
    const finalStatusB = await fetch(statusUrlB, { headers: { authorization: "Bearer admin-key" } });
    assert.equal(finalStatusA.status, 200);
    assert.equal(finalStatusB.status, 200);
    assert.deepEqual((await finalStatusA.json() as any).queue, []);
    assert.deepEqual((await finalStatusB.json() as any).queue, []);
  } finally {
    await Promise.all([
      new Promise<void>((resolve) => serverA.close(() => resolve())),
      new Promise<void>((resolve) => serverB.close(() => resolve())),
    ]);
  }
});

