async function assertPlatformCiArtifactImportRejectsIncompleteEvidence(options: {
  tempName: string;
  reportName: string;
  phase: "pre-serve" | "post-serve";
  completeEvidence: Record<string, unknown>;
  incompleteEvidence: Record<string, unknown>;
  operatorApprovals?: unknown[];
  externalTargets?: Record<string, unknown>;
  checks?: {
    preServe?: string[];
    postServe?: string[];
  };
}): Promise<void> {
  const root = await tempDir(options.tempName);
  const outDir = join(root, "cutover-bundle");
  const artifactRoot = join(root, "downloaded-artifact");
  const artifactReports = join(artifactRoot, "reports");
  const reportDir = join(outDir, "reports");
  const reportPath = join(reportDir, "ci-artifact-import.json");
  const staleReportPath = join(reportDir, options.reportName);
  const artifactReportPath = join(artifactReports, options.reportName);
  await mkdir(dirname(artifactReportPath), { recursive: true });
  await mkdir(dirname(staleReportPath), { recursive: true });
  await mkdir(outDir, { recursive: true });
  await writeFile(join(outDir, "staging-ci.json"), `${JSON.stringify({
    schemaVersion: "platform-staging-ci/v1",
    tokenFree: true,
    commands: {
      preServe: "LOOM_CUTOVER_PHASE=pre-serve ./commands.sh",
      postServe: "LOOM_CUTOVER_PHASE=post-serve ./commands.sh",
      all: "./commands.sh",
    },
    requiredEnv: [],
    externalTargets: options.externalTargets ?? {},
    expectedReports: {
      preServe: options.phase === "pre-serve" ? [options.reportName] : [],
      postServe: options.phase === "post-serve" ? [options.reportName] : [],
    },
    operatorApprovals: options.operatorApprovals ?? [],
    checks: {
      preServe: options.checks?.preServe ?? [],
      postServe: options.checks?.postServe ?? [],
    },
  }, null, 2)}\n`, "utf8");
  await writeFile(staleReportPath, `${JSON.stringify(options.completeEvidence, null, 2)}\n`, "utf8");
  await writeFile(artifactReportPath, `${JSON.stringify({
    ...options.incompleteEvidence,
    tokenPreview: "bundle-secret-value",
  }, null, 2)}\n`, "utf8");

  const imported = await execa(
    "npx",
    [
      "tsx",
      "src/index.ts",
      "harness",
      "platform-ci-artifact-import",
      "--dir",
      outDir,
      "--artifact-dir",
      artifactRoot,
      "--phase",
      options.phase,
      "--report",
      reportPath,
    ],
    { cwd: process.cwd(), reject: false },
  );

  assert.equal(imported.exitCode, 1);
  assert.equal(imported.stdout.includes("bundle-secret-value"), false);
  const body = JSON.parse(imported.stdout);
  assert.equal(body.schemaVersion, "platform-ci-artifact-import/v1");
  assert.equal(body.ok, false);
  assert.deepEqual(body.allowedReports, [options.reportName]);
  assert.deepEqual(body.invalidReports, [options.reportName]);
  assert.deepEqual(body.missing, [`reports.${options.reportName}.json`]);
  assert.deepEqual(JSON.parse(await readFile(reportPath, "utf8")), body);
  await assert.rejects(() => readFile(staleReportPath, "utf8"), /ENOENT/);
}

