test("loom harness platform-staging-prerequisites checks the operator shell before external staging", async () => {
  const root = await tempDir("loom-cli-platform-staging-prerequisites");
  const planPath = join(root, "plan.json");
  const outDir = join(root, "bundle");
  const reportPath = join(outDir, "reports", "staging-prerequisites.json");
  const loomBin = join(root, "loom-bin");
  const missingLoomBin = join(root, "missing-loom-bin");
  const plan = {
    ok: true,
    profile: "platform-readiness",
    tenant: "alice",
    project: "vas",
    serverUrl: "https://loom.example",
    controlPlaneProvider: "agent-git-service",
    sensitiveInputsOmitted: [],
    externalEnvironment: {
      tokenFree: true,
      systems: {
        modelGateway: { baseUrl: "https://litellm.staging.acme.dev/v1" },
        executor: { kind: "coder" },
        controlPlane: {
          provider: "agent-git-service",
          baseUrl: "https://ags.staging.acme.dev/api/v3",
          tokenEnv: "LOOM_AUDIT_TOKEN",
        },
        agentGitServiceStaging: {
          issue: "team/vas#42",
          repo: "team/vas",
          wikiPage: "vas/audit",
        },
      },
      requiredVariables: [
        {
          name: "LOOM_AUDIT_TOKEN",
          requiredFor: ["platform-preflight", "agent-git-service-staging-readiness"],
          uses: [{ sourceFlag: "--control-plane-token-env", purpose: "agent-git-service control-plane token" }],
        },
      ],
    },
    stages: [
      cutoverRunnerStage("platform-preflight", "read-only", false, "preflight"),
      cutoverCompatRunnerStage("compat", {
        candidateMode: "upstream",
        candidateBaseUrl: "https://ags.staging.acme.dev/api/v3",
      }),
      cutoverRunnerStage("agent-git-service-staging-readiness", "read-only", false, "staging"),
      {
        id: "serve",
        command: "loom harness serve",
        commandArgs: ["loom", "harness", "serve"],
        executionMode: "long-running",
        approvalRequired: true,
        tokenFree: true,
        operatorGate: {
          id: "serve-running",
          evidence: "external serve is reachable",
        },
      },
    ],
  };
  await writeFile(planPath, `${JSON.stringify(plan, null, 2)}\n`, "utf8");

  const bundle = await execa(
    "npx",
    ["tsx", "src/index.ts", "harness", "platform-cutover-bundle", "--plan", planPath, "--out", outDir],
    { cwd: process.cwd(), reject: false },
  );
  assert.equal(bundle.exitCode, 0, bundle.stderr || bundle.stdout);
  const wrapperPath = join(outDir, "loom-wrapper");
  await writeFile(wrapperPath, "#!/usr/bin/env sh\nexit 0\n", "utf8");
  await chmod(wrapperPath, 0o755);

  const missing = await execa(
    "npx",
    [
      "tsx",
      "src/index.ts",
      "harness",
      "platform-staging-prerequisites",
      "--dir",
      outDir,
      "--require-agent-git-service",
      "--report",
      reportPath,
    ],
    {
      cwd: process.cwd(),
      env: {
        ...process.env,
        LOOM_BIN: missingLoomBin,
        LOOM_AUDIT_TOKEN: "",
        DB_DSN: "",
      },
      reject: false,
    },
  );
  assert.equal(missing.exitCode, 1);
  const missingBody = JSON.parse(missing.stdout);
  assert.equal(missingBody.schemaVersion, "platform-staging-prerequisites/v1");
  assert.equal(missingBody.ok, false);
  assert.equal(missingBody.tokenFree, true);
  assert.equal(missingBody.gates.bundleOk, true);
  assert.equal(missingBody.gates.strictCommandsOk, true);
  assert.equal(missingBody.gates.environmentOk, false);
  assert.equal(missingBody.gates.toolingOk, false);
  assert.equal(missingBody.gates.externalTargetsReady, true);
  assert.equal(missingBody.gates.upstreamAgentGitServiceOk, false);
  assert.deepEqual(missingBody.env.missing.map((item: any) => item.name), ["LOOM_AUDIT_TOKEN"]);
  assert.ok(missingBody.missing.includes("environment.LOOM_AUDIT_TOKEN"));
  assert.ok(missingBody.missing.includes("tooling.LOOM_BIN"));
  assert.ok(missingBody.missing.includes("upstreamAgentGitService.requiredServerEnv.DB_DSN"));
  assert.equal(
    missingBody.upstreamAgentGitService.requiredServerEnv.find((item: any) => item.name === "DB_DSN").present,
    false,
  );
  assert.equal(missingBody.tooling.loomBin.suggestedWrapperPath, wrapperPath);
  assert.equal(missingBody.tooling.loomBin.suggestedExportCommand, `export LOOM_BIN=${wrapperPath}`);
  assert.deepEqual(missingBody.nextActions, [
    "Set required env vars: LOOM_AUDIT_TOKEN",
    `Export LOOM_BIN=${wrapperPath} before running commands.sh.`,
    `Run upstream server env plan: ${wrapperPath} harness upstream-agent-git-service-server-env-plan --dir ${outDir} --report ${join(outDir, "reports", "upstream-agent-git-service-server-env-plan.json")}; start gh-server with serverStartShellCommand, then rerun platform-staging-prerequisites.`,
  ]);
  assert.deepEqual(JSON.parse(await readFile(reportPath, "utf8")), missingBody);

  const envWithoutLoomBin = { ...process.env };
  delete envWithoutLoomBin.LOOM_BIN;
  const bundledWrapper = await execa(
    "npx",
    [
      "tsx",
      "src/index.ts",
      "harness",
      "platform-staging-prerequisites",
      "--dir",
      outDir,
      "--require-agent-git-service",
      "--report",
      reportPath,
    ],
    {
      cwd: process.cwd(),
      env: {
        ...envWithoutLoomBin,
        LOOM_AUDIT_TOKEN: "",
        DB_DSN: "",
      },
      reject: false,
    },
  );
  assert.equal(bundledWrapper.exitCode, 1);
  const bundledWrapperBody = JSON.parse(bundledWrapper.stdout);
  assert.equal(bundledWrapperBody.gates.toolingOk, true);
  assert.equal(bundledWrapperBody.tooling.loomBin.command, wrapperPath);
  assert.equal(bundledWrapperBody.tooling.loomBin.available, true);
  assert.equal(bundledWrapperBody.tooling.loomBin.suggestedWrapperPath, undefined);
  assert.equal(bundledWrapperBody.tooling.loomBin.suggestedExportCommand, undefined);
  assert.equal(bundledWrapperBody.missing.includes("tooling.LOOM_BIN"), false);
  assert.equal(
    bundledWrapperBody.nextActions.some((action: string) => action.includes("LOOM_BIN")),
    false,
  );
  assert.ok(bundledWrapperBody.nextActions.includes(
    `Run upstream server env plan: ${wrapperPath} harness upstream-agent-git-service-server-env-plan --dir ${outDir} --report ${join(outDir, "reports", "upstream-agent-git-service-server-env-plan.json")}; start gh-server with serverStartShellCommand, then rerun platform-staging-prerequisites.`,
  ));

  await writeFile(loomBin, "#!/usr/bin/env sh\nexit 0\n", "utf8");
  await chmod(loomBin, 0o755);
  const controlPlaneSecret = "audit-secret-value";
  const dbSecret = "db-secret-value";
  const ready = await execa(
    "npx",
    [
      "tsx",
      "src/index.ts",
      "harness",
      "platform-staging-prerequisites",
      "--dir",
      outDir,
      "--require-agent-git-service",
      "--report",
      reportPath,
      "--forbid-env",
      "LOOM_AUDIT_TOKEN",
      "--forbid-env",
      "DB_DSN",
    ],
    {
      cwd: process.cwd(),
      env: {
        ...process.env,
        LOOM_BIN: loomBin,
        LOOM_AUDIT_TOKEN: controlPlaneSecret,
        DB_DSN: dbSecret,
      },
      reject: false,
    },
  );
  assert.equal(ready.exitCode, 0, ready.stderr || ready.stdout);
  assert.equal(ready.stdout.includes(controlPlaneSecret), false);
  assert.equal(ready.stdout.includes(dbSecret), false);
  const readyBody = JSON.parse(ready.stdout);
  assert.equal(readyBody.ok, true);
  assert.deepEqual(readyBody.missing, []);
  assert.deepEqual(readyBody.nextActions, []);
  assert.equal(readyBody.gates.bundleOk, true);
  assert.equal(readyBody.gates.strictCommandsOk, true);
  assert.equal(readyBody.gates.environmentOk, true);
  assert.equal(readyBody.gates.toolingOk, true);
  assert.equal(readyBody.gates.externalTargetsReady, true);
  assert.equal(readyBody.gates.upstreamAgentGitServiceOk, true);
  assert.equal(readyBody.tooling.loomBin.command, loomBin);
  assert.equal(readyBody.tooling.jq.available, true);
  assert.equal(
    readyBody.upstreamAgentGitService.requiredServerEnv.find((item: any) => item.name === "DB_DSN").present,
    true,
  );
  assert.equal(readyBody.strictPreServeCommand, "LOOM_REQUIRE_EXTERNAL_STAGING=1 LOOM_REQUIRE_OPERATOR_APPROVALS=1 LOOM_RUN_STAGING_CI_CHECKS=1 LOOM_CUTOVER_PHASE=pre-serve ./commands.sh");
  assert.deepEqual(JSON.parse(await readFile(reportPath, "utf8")), readyBody);
});

test("loom harness platform-staging-prerequisites points placeholder target gaps at the replacement plan", async () => {
  const root = await tempDir("loom-cli-platform-staging-prerequisites-target-plan");
  const planPath = join(root, "plan.json");
  const outDir = join(root, "bundle");
  const reportPath = join(outDir, "reports", "staging-prerequisites.json");
  const loomBin = join(root, "loom-bin");
  await writeFile(planPath, `${JSON.stringify({
    ok: true,
    profile: "platform-readiness",
    externalEnvironment: {
      tokenFree: true,
      systems: {
        modelGateway: { baseUrl: "https://litellm.example/v1" },
        executor: { kind: "coder" },
        controlPlane: {
          provider: "agent-git-service",
          baseUrl: "https://ags.example/api/v3",
          tokenEnv: "LOOM_AGENT_GIT_SERVICE_TOKEN",
        },
        agentGitServiceStaging: {
          issue: "team/app#1",
          repo: "team/app",
          wikiPage: "vas/learnings",
          nativeWriteAttachmentUrl: "https://evidence.example/loom/ags-native-write",
        },
      },
      requiredVariables: [],
    },
    stages: [
      cutoverRunnerStage("agent-git-service-staging-readiness", "read-only", false, "staging"),
    ],
  }, null, 2)}\n`, "utf8");

  const bundle = await execa(
    "npx",
    ["tsx", "src/index.ts", "harness", "platform-cutover-bundle", "--plan", planPath, "--out", outDir],
    { cwd: process.cwd(), reject: false },
  );
  assert.equal(bundle.exitCode, 0, bundle.stderr || bundle.stdout);
  const wrapperPath = join(outDir, "loom-wrapper");
  await writeFile(wrapperPath, "#!/usr/bin/env sh\nexit 0\n", "utf8");
  await chmod(wrapperPath, 0o755);
  await writeFile(loomBin, "#!/usr/bin/env sh\nexit 0\n", "utf8");
  await chmod(loomBin, 0o755);

  const checked = await execa(
    "npx",
    [
      "tsx",
      "src/index.ts",
      "harness",
      "platform-staging-prerequisites",
      "--dir",
      outDir,
      "--require-agent-git-service",
      "--report",
      reportPath,
    ],
    {
      cwd: process.cwd(),
      env: { ...process.env, LOOM_BIN: loomBin, DB_DSN: "db-secret-value" },
      reject: false,
    },
  );

  assert.equal(checked.exitCode, 1);
  assert.equal(checked.stdout.includes("db-secret-value"), false);
  const body = JSON.parse(checked.stdout);
  assert.equal(body.gates.environmentOk, true);
  assert.equal(body.gates.toolingOk, true);
  assert.equal(body.gates.upstreamAgentGitServiceOk, true);
  assert.equal(body.gates.externalTargetsReady, false);
  assert.deepEqual(body.stagingTargets.placeholderTargets, [
    "targets.modelGateway.placeholder",
    "targets.controlPlane.placeholder",
    "targets.agentGitServiceStaging.issue.placeholder",
    "targets.agentGitServiceStaging.repo.placeholder",
    "targets.agentGitServiceStaging.nativeWriteAttachmentUrl.placeholder",
  ]);
  assert.deepEqual(body.missing, body.stagingTargets.placeholderTargets);
  assert.deepEqual(body.nextActions, [
    `Run staging target replacement plan: ${loomBin} harness platform-staging-targets-plan --dir ${outDir} --report ${join(outDir, "reports", "staging-targets-plan.json")}; export requiredEnvNames or write inputTemplatePath, run applyCommandArgs/applyInputCommandArgs, regenerate the bundle, then rerun platform-staging-prerequisites.`,
  ]);
  assert.deepEqual(JSON.parse(await readFile(reportPath, "utf8")), body);

  const audit = await execa(
    "npx",
    [
      "tsx",
      "src/index.ts",
      "harness",
      "platform-external-staging-audit",
      "--dir",
      outDir,
    ],
    { cwd: process.cwd(), reject: false },
  );
  assert.equal(audit.exitCode, 1);
  const auditBody = JSON.parse(audit.stdout);
  assert.equal(auditBody.gates.externalTargetsReady, false);
  assert.ok(auditBody.nextActions.includes(
    `Run staging target replacement plan: ${wrapperPath} harness platform-staging-targets-plan --dir ${outDir} --report ${join(outDir, "reports", "staging-targets-plan.json")}; export requiredEnvNames or write inputTemplatePath, run applyCommandArgs/applyInputCommandArgs, regenerate the bundle, then rerun platform-staging-prerequisites.`,
  ));
});

test("loom harness platform-staging-verdict turns pre-serve evidence into operator next actions", async () => {
  const root = await tempDir("loom-cli-platform-staging-verdict");
  const evidencePath = join(root, "reports", "staging-evidence.json");
  const verdictPath = join(root, "reports", "staging-verdict.json");
  await mkdir(join(root, "reports"), { recursive: true });
  const readyEvidence = {
    schemaVersion: "platform-staging-evidence/v1",
    tokenFree: true,
    ok: true,
    reportDir: join(root, "reports"),
    reports: {
      platformPreflight: {
        name: "platform-preflight.json",
        path: join(root, "reports", "platform-preflight.json"),
        exists: true,
        sha256: "a".repeat(64),
        ok: true,
      },
      agentGitServiceStagingReadiness: {
        name: "agent-git-service-staging-readiness.json",
        path: join(root, "reports", "agent-git-service-staging-readiness.json"),
        exists: true,
        sha256: "b".repeat(64),
        ok: true,
      },
    },
    gates: {
      doctorPreflightOk: true,
      modelGatewayReady: true,
      controlPlaneReady: true,
      coderReady: true,
      agentGitServiceStagingReady: true,
      agentGitServiceCompatOk: true,
      preServeEvidenceOk: true,
    },
    forbiddenValueHitReports: [],
    missing: [],
  };
  await writeFile(evidencePath, `${JSON.stringify(readyEvidence, null, 2)}\n`, "utf8");

  const ready = await execa(
    "npx",
    [
      "tsx",
      "src/index.ts",
      "harness",
      "platform-staging-verdict",
      "--evidence",
      evidencePath,
      "--report",
      verdictPath,
    ],
    { cwd: process.cwd(), reject: false },
  );

  assert.equal(ready.exitCode, 0, ready.stderr || ready.stdout);
  const readyBody = JSON.parse(ready.stdout);
  assert.equal(readyBody.schemaVersion, "platform-staging-verdict/v1");
  assert.equal(readyBody.ok, true);
  assert.equal(readyBody.tokenFree, true);
  assert.equal(readyBody.decision, "ready-for-serve");
  assert.equal(readyBody.approvedFor, "manual-serve-start");
  assert.equal(readyBody.evidencePath, evidencePath);
  assert.match(readyBody.evidenceSha256, /^[a-f0-9]{64}$/);
  assert.deepEqual(readyBody.missing, []);
  assert.deepEqual(readyBody.failedGates, []);
  assert.deepEqual(readyBody.forbiddenValueHitReports, []);
  assert.deepEqual(readyBody.nextActions, [
    "Start the manual long-running serve stage from the operator bundle.",
    "After serve is reachable, run the post-serve serve-ready, cutover-report, and smoke stages.",
  ]);
  assert.deepEqual(JSON.parse(await readFile(verdictPath, "utf8")), readyBody);

  await writeFile(evidencePath, `${JSON.stringify({
    ...readyEvidence,
    ok: false,
    gates: {
      ...readyEvidence.gates,
      modelGatewayReady: false,
      preServeEvidenceOk: false,
    },
    forbiddenValueHitReports: ["platform-preflight.json"],
    missing: ["platformPreflight.gates.model", "forbiddenValueHitReports"],
  }, null, 2)}\n`, "utf8");
  const blocked = await execa(
    "npx",
    [
      "tsx",
      "src/index.ts",
      "harness",
      "platform-staging-verdict",
      "--evidence",
      evidencePath,
    ],
    { cwd: process.cwd(), reject: false },
  );

  assert.equal(blocked.exitCode, 1);
  const blockedBody = JSON.parse(blocked.stdout);
  assert.equal(blockedBody.ok, false);
  assert.equal(blockedBody.decision, "blocked");
  assert.deepEqual(blockedBody.failedGates, ["modelGatewayReady", "preServeEvidenceOk"]);
  assert.deepEqual(blockedBody.missing, ["platformPreflight.gates.model", "forbiddenValueHitReports"]);
  assert.deepEqual(blockedBody.forbiddenValueHitReports, ["platform-preflight.json"]);
  assert.deepEqual(blockedBody.nextActions, [
    "Fix failed pre-serve gates: modelGatewayReady, preServeEvidenceOk.",
    "Restore missing evidence: platformPreflight.gates.model, forbiddenValueHitReports.",
    "Remove forbidden secret material from reports: platform-preflight.json.",
    "Rerun LOOM_CUTOVER_PHASE=pre-serve ./commands.sh.",
  ]);
});

test("loom harness platform-serve-ready writes token-free post-serve gate evidence", async (t) => {
  const root = await tempDir("loom-cli-platform-serve-ready");
  const reportPath = join(root, "serve-ready.json");
  const planPath = join(root, "plan.json");
  const server = createServer((req, res) => {
    res.setHeader("content-type", "application/json");
    if (req.url === "/healthz") {
      res.end(JSON.stringify({ ok: true, startedAt: "2026-07-02T00:00:00.000Z", uptimeMs: 12 }));
      return;
    }
    if (req.url === "/readyz") {
      res.end(JSON.stringify({ ready: true, startedAt: "2026-07-02T00:00:00.000Z", uptimeMs: 13, checks: { config: true } }));
      return;
    }
    if (req.url === "/status") {
      if (req.headers.authorization !== "Bearer serve-ready-secret") {
        res.statusCode = 401;
        res.end(JSON.stringify({ error: "invalid token" }));
        return;
      }
      res.end(JSON.stringify({ readiness: { profile: "platform-readiness", ok: true, missing: [] } }));
      return;
    }
    res.statusCode = 404;
    res.end(JSON.stringify({ ok: false }));
  });
  await new Promise<void>((resolve) => server.listen(0, "127.0.0.1", resolve));
  t.after(() => new Promise<void>((resolve, reject) => server.close((error) => error ? reject(error) : resolve())));
  const address = server.address();
  assert.equal(typeof address, "object");
  assert.ok(address);
  const serverUrl = `http://127.0.0.1:${address.port}`;
  await writeFile(planPath, JSON.stringify({
    ok: true,
    profile: "platform-readiness",
    serverUrl,
    externalEnvironment: {
      tokenFree: true,
      requiredVariables: [
        {
          name: "LOOM_SERVE_READY_TOKEN",
          requiredFor: ["cutover-report"],
          uses: [{ sourceFlag: "--token-env", purpose: "developer tenant token", tenant: "alice" }],
        },
      ],
    },
    stages: [],
  }), "utf8");

  const result = await execa(
    "npx",
    [
      "tsx",
      "src/index.ts",
      "harness",
      "platform-serve-ready",
      "--plan",
      planPath,
      "--report",
      reportPath,
    ],
    {
      cwd: process.cwd(),
      env: { ...process.env, LOOM_SERVE_READY_TOKEN: "serve-ready-secret" },
      reject: false,
    },
  );

  assert.equal(result.exitCode, 0, result.stderr || result.stdout);
  assert.equal(result.stdout.includes("serve-ready-secret"), false);
  const body = JSON.parse(result.stdout);
  assert.equal(body.schemaVersion, "platform-serve-ready/v1");
  assert.equal(body.ok, true);
  assert.equal(body.tokenFree, true);
  assert.equal(body.url, serverUrl);
  assert.equal(body.expectedProfile, "platform-readiness");
  assert.equal(body.profile, "platform-readiness");
  assert.deepEqual(body.missing, []);
  assert.equal(body.healthz.ok, true);
  assert.equal(body.readyz.ready, true);
  assert.equal(body.status.readinessOk, true);
  assert.equal(body.status.tokenEnvName, "LOOM_SERVE_READY_TOKEN");
  assert.deepEqual(JSON.parse(await readFile(reportPath, "utf8")), body);
});

