  assert.ok(stagingCi.checks.postServe.includes("jq -e '.ok == true and .gates.operatorApprovalsOk == true' reports/operator-artifacts.json"));
  assert.ok(stagingCi.checks.postServe.includes("jq -e '(.expectedReports.preServe + .expectedReports.postServe - [\"operator-artifacts.json\", \"staging-proof.json\", \"goal-audit.json\", \"operator-cockpit-plan.json\", \"operator-cockpit-next.json\", \"operator-handoff-packet.json\"] | unique) as $expected | input as $artifacts | (($expected - $artifacts.requiredReports) | length == 0) and ([ $artifacts.reports[]? | select(.name as $name | $expected | index($name)) | select(.ok == true and ((.sha256 // \"\") | test(\"^[a-f0-9]{64}$\"))) | .name] | unique | length) == ($expected | length)' staging-ci.json reports/operator-artifacts.json"));
  assert.ok(stagingCi.checks.postServe.includes(STRICT_STAGING_PROOF_ROLLUP_CHECK));
  assert.ok(stagingCi.checks.postServe.includes("jq -e '.ok == true and .gates.operatorApprovalsOk == true' reports/staging-proof.json"));
