  assert.ok(commands.includes("\"${LOOM_BIN}\" harness platform-operator-cockpit-next --dir . --report reports/operator-cockpit-next.json \"${GOAL_AUDIT_EXTRA_ARGS[@]}\""));
  assert.ok(commands.includes("\"${LOOM_BIN}\" harness platform-operator-handoff-packet --dir . --report reports/operator-handoff-packet.json \"${GOAL_AUDIT_EXTRA_ARGS[@]}\""));
  assert.ok(commands.indexOf("platform-operator-status --dir .") < commands.indexOf("platform-operator-cockpit-plan --dir ."));
  assert.ok(commands.indexOf("platform-operator-cockpit-plan --dir .") < commands.indexOf("platform-operator-cockpit-next --dir ."));
  assert.ok(commands.indexOf("platform-operator-cockpit-next --dir .") < commands.indexOf("platform-operator-handoff-packet --dir ."));
  assert.ok(commands.indexOf("platform-operator-handoff-packet --dir .") < commands.indexOf('run_staging_ci_checks "postServe"'));
