  const postServeScriptLogPath = join(root, "post-serve-script.log");
  const loomBinPath = join(root, "loom-bin");
  const serveReadyServer = createServer((req, res) => {
    res.setHeader("content-type", "application/json");
    if (req.url === "/healthz") {
      res.end(JSON.stringify({ ok: true, startedAt: "2026-07-02T00:00:00.000Z", uptimeMs: 12 }));
      return;
    }
    if (req.url === "/readyz") {
      res.end(JSON.stringify({ ready: true, startedAt: "2026-07-02T00:00:00.000Z", uptimeMs: 13, checks: { config: true } }));
      return;
    }
    if (req.url === "/status") {
      res.end(JSON.stringify({ readiness: { profile: "platform-readiness", ok: true, missing: [] } }));
      return;
    }
    res.statusCode = 404;
    res.end(JSON.stringify({ ok: false }));
  });
  await new Promise<void>((resolve) => serveReadyServer.listen(0, "127.0.0.1", resolve));
